import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void binaryTen() {
        assertEquals("1010", new Solution().toBase(10, 2));
    }

    @Test
    void hexByteBoundary() {
        // 255 is the maximum unsigned byte value
        assertEquals("FF", new Solution().toBase(255, 16));
    }

    @Test
    void zeroInBase2() {
        assertEquals("0", new Solution().toBase(0, 2));
    }

    @Test
    void zeroInBase16() {
        assertEquals("0", new Solution().toBase(0, 16));
    }

    @Test
    void singleDigitBase2() {
        assertEquals("1", new Solution().toBase(1, 2));
    }

    @Test
    void base36Mixed() {
        assertEquals("2S", new Solution().toBase(100, 36));
    }

    @Test
    void noLeadingZeros() {
        // 8 in base 2 is "1000", not "01000"
        assertEquals("1000", new Solution().toBase(8, 2));
    }
}
